const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// --- Security Middleware ---

// Set secure HTTP headers (XSS protection, clickjacking prevention, etc.)
app.use(helmet());

// Parse JSON bodies with a size limit to prevent large-payload attacks
app.use(express.json({ limit: '10kb' }));

// Global rate limiter: 100 requests per 15 minutes per IP
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// Disable the X-Powered-By header to avoid fingerprinting
app.disable('x-powered-by');

// --- Routes ---

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Validate optional query parameter: id must be a positive integer
  if (req.query.id !== undefined) {
    const id = Number(req.query.id);
    if (!Number.isInteger(id) || id <= 0) {
      return res.status(400).json({ error: 'Invalid user id. Must be a positive integer.' });
    }
  }

  const users = [
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ];

  // Filter by id if provided
  if (req.query.id) {
    const user = users.find((u) => u.id === Number(req.query.id));
    if (!user) {
      return res.status(404).json({ error: 'User not found.' });
    }
    return res.json(user);
  }

  res.json(users);
});

// --- 404 Handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not found.' });
});

// --- Global Error Handler ---
// Catches unhandled errors and avoids leaking stack traces to clients
app.use((err, req, res, _next) => {
  console.error('Unhandled error:', err.message);
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error.'
      : err.message,
  });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;

