  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});
```

**Recommendation:** Add authentication middleware (e.g., JWT verification) and authorize per-endpoint:

```js
const jwt = require('jsonwebtoken');

function authenticate(req, res, next) {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Authentication required' });
  }
  try {
    const token = authHeader.split(' ')[1];
    req.user = jwt.verify(token, process.env.JWT_SECRET);
    next();
  } catch (err) {
    return res.status(401).json({ error: 'Invalid or expired token' });
  }
}

app.get('/users', authenticate, (req, res) => {
  // Return only the fields the caller is authorized to see
  res.json(users.map(({ id, name }) => ({ id, name })));
});
```

### 2. Information Disclosure — PII Exposure (OWASP A01 / A04)

Even with authentication, returning raw email addresses in a list endpoint is a data minimization violation. Email harvesting and phishing are direct risks.

**Recommendation:** Only return emails when the authenticated user is viewing their own profile, or when the caller has admin privileges.

